return ['domain'=>NULL,'plural-forms'=>'nplurals=3; plural=(n==1 ? 0 : (n==0 || (n%100 > 0 && n%100 < 20)) ? 1 : 2);','language'=>'ro_RO','project-id-version'=>'TranslatePress Multilingual','pot-creation-date'=>'2026-05-25T19:29:27+03:00','po-revision-date'=>'2026-05-25T19:29:27+03:00','x-generator'=>'TranslatePress build (community + OpenRouter), 2026-05-25','messages'=>['Please update the TranslatePress - Multilingual plugin to version %1$s or higher to ensure %2$s functions correctly.'=>'Te rugăm să actualizezi pluginul TranslatePress - Multilingual la versiunea %1$s sau o versiune ulterioară pentru a te asigura că %2$s funcționează corect.','Please install and activate the TranslatePress - Multilingual plugin'=>'Te rugăm să instalezi și să activezi pluginul TranslatePress - Multilingual','Install & Activate'=>'Instalează și activează','Please update TranslatePress - Multilingual to version %2$s or newer. Your currently installed version of TranslatePress - Multilingual is no longer compatible with the current version of %1$s.'=>'Te rugăm să actualizezi TranslatePress - Multilingual la versiunea %2$s sau o versiune mai nouă. Versiunea ta curentă de TranslatePress - Multilingual nu mai este compatibilă cu versiunea actuală de %1$s.','All TranslatePress functionalities are disabled until then.'=>'Toate funcționalitățile TranslatePress sunt dezactivate până atunci.','Update Now'=>'Actualizează acum','This TranslatePress add-on has been migrated to the main plugin and is no longer used. You can delete it.'=>'Această extensie TranslatePress a fost migrată în pluginul principal și nu mai este utilizată. O poți șterge.','<strong>TranslatePress</strong> requires at least PHP version 5.6.20+ to run. It is the <a href="%s">minimum requirement of the latest WordPress version</a>. Please contact your server administrator to update your PHP version.'=>'<strong>TranslatePress</strong> necesită cel puțin versiunea PHP 5.6.20+ pentru a funcționa. Aceasta este <a href="%s">cerința minimă a celei mai recente versiuni WordPress</a>. Te rugăm să contactezi administratorul serverului pentru a actualiza versiunea ta de PHP.','Advanced'=>'Avansate','Settings saved.'=>'Setările au fost salvate.','Are you sure you want to remove this item?'=>'Ești sigur că vrei să elimini acest element?','Remove'=>'Elimină','Add'=>'Adaugă','Select...'=>'Selectează...','[%s] Low TranslatePress AI Words'=>'[%s] Cuvinte TranslatePress AI pe terminate','upgrade your plan or get extra AI Words'=>'actualizează-ți planul sau obține cuvinte AI suplimentare','upgrade your plan'=>'actualizează-ți planul','TranslatePress AI words are running low on your site.'=>'Cuvintele TranslatePress AI de pe site-ul tău sunt pe terminate.','Current status: %s words remaining'=>'Stare actuală: %s cuvinte rămase','Once the remaining AI words run out, automatic translation through TranslatePress AI will be paused.'=>'Odată ce cuvintele AI rămase se epuizează, traducerea automată prin TranslatePress AI va fi suspendată.','To continue translating your content, please %1$s over at %2$s'=>'Pentru a continua traducerea conținutului, te rugăm să %1$s la %2$s','Manage Notification: %s'=>'Gestionează notificarea: %s','There is a new version of %1$s available. %2$sView version %3$s details%4$s or %5$supdate now%6$s.'=>'Este disponibilă o nouă versiune de %1$s. %2$sVezi detaliile versiunii %3$s%4$s sau %5$sactualizează acum%6$s.','There is a new version of %1$s available. %2$sView version %3$s details%4$s.'=>'Este disponibilă o nouă versiune de %1$s. %2$sVezi detaliile versiunii %3$s%4$s.','To enable updates, please %1$senter your license key%2$s. Need a license key? %3$sPurchase one now%4$s.'=>'Pentru a activa actualizările, te rugăm să %1$sintroduci cheia ta de licență%2$s. Ai nevoie de o cheie de licență? %3$sCumpără una acum%4$s.','To enable updates, please go to the %1$slicense page%2$s and check that you have a valid license.'=>'Pentru a activa actualizările, te rugăm să mergi la %1$spagina de licență%2$s și să verifici că ai o licență validă.','To enable updates, your licence needs to be renewed. Please go to the %1$sTranslatePress Account%2$s page and login to renew.'=>'Pentru a activa actualizările, licența ta trebuie reînnoită. Te rugăm să mergi la pagina %1$sTranslatePress Account%2$s și să te autentifici pentru a reînnoi.','You do not have permission to install plugin updates'=>'Nu ai permisiunea de a instala actualizări de pluginuri','Error'=>'Eroare','Your TranslatePress license key is invalid or missing.'=>'Cheia ta de licență TranslatePress este invalidă sau lipsește.','Your license key expired on %s.'=>'Cheia ta de licență a expirat pe %s.','Your license key has been disabled.'=>'Cheia ta de licență a fost dezactivată.','Your license key is disabled for this URL. Re-enable it from <a target="_blank" href="https://translatepress.com/account/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=license-deactivated">https://translatepress.com/account</a> -> Manage Sites.'=>'Cheia ta de licență este dezactivată pentru acest URL. Reactiveaz-o din <a target="_blank" href="https://translatepress.com/account/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=license-deactivated">https://translatepress.com/account</a> -> Gestionează site-urile.','<p><strong>License key mismatch.</strong> The license you entered doesn’t match the TranslatePress version you have installed.</p><p>Please check that you’ve installed the correct version for your license from your TranslatePress account.</p>'=>'<p><strong>Cheia de licență nu corespunde.</strong> Licența introdusă nu corespunde cu versiunea TranslatePress instalată.</p><p>Te rugăm să verifici că ai instalat versiunea corectă pentru licența ta din contul tău TranslatePress.</p>','If you have only the free plugin installed but added a paid license, please install the paid plugin from your TranslatePress account.'=>'Dacă ai instalat doar pluginul gratuit, dar ai adăugat o licență plătită, te rugăm să instalezi pluginul plătit din contul tău TranslatePress.','Your license key has reached its activation limit.'=>'Cheia ta de licență a atins limita de activare.','Upgrade your plan to add more sites. %1$sUpgrade now%2$s'=>'Upgradează-ți planul pentru a adăuga mai multe site-uri. %1$sUpgradează acum%2$s','This website is already activated under a free license. Each website can only use one free license.'=>'Acest site web este deja activat sub o licență gratuită. Fiecare site web poate folosi doar o singură licență gratuită.','An error occurred, please try again.'=>'A apărut o eroare, te rugăm să încerci din nou.','You have successfully activated your license'=>'Ai activat cu succes licența','Others'=>'Altele','Restrict by Language'=>'Restricționează după limbă','Exclude from Language'=>'Exclude din limbă','Restrict element to language'=>'Restricționează elementul la limbă','Show this element only in one language.'=>'Afișează acest element doar într-o limbă.','Enable translation'=>'Activează traducerea','Allow translation to the corresponding language only if the content is written in the default language.'=>'Permite traducerea în limba corespunzătoare doar dacă conținutul este scris în limba implicită.','Select language'=>'Selectează limba','Choose in which language to show this element.'=>'Alege limba în care să se afișeze acest element.','Exclude element from language'=>'Exclude elementul din limbă','Exclude this element from specific languages.'=>'Exclude acest element din anumite limbi.','Select languages'=>'Selectează limbile','Choose from which languages to exclude this element.'=>'Alege din ce limbi să excluzi acest element.','This element will still be visible when you are translating your website through the Translation Editor.'=>'Acest element va rămâne vizibil atunci când traduci site-ul prin Editorul de traduceri.','The content of this element should be written in the default language.'=>'Conținutul acestui element trebuie scris în limba implicită.','<strong>TranslatePress</strong> encountered SQL errors. <a href="%s" title="View TranslatePress SQL Errors">Check out the errors</a>.'=>'<strong>TranslatePress</strong> a întâmpinat erori SQL. <a href="%s" title="View TranslatePress SQL Errors">Consultă erorile</a>.','Automatic translation has been disabled.'=>'Traducerea automată a fost dezactivată.','Dismiss this notice.'=>'Închide această notificare.','Logged errors'=>'Erori înregistrate','These are the most recent 5 errors logged by TranslatePress:'=>'Acestea sunt cele mai recente 5 erori înregistrate de TranslatePress:','Yes'=>'Da','Why are these errors occuring'=>'De ce apar aceste erori','If TranslatePress detects something wrong when executing queries on your database, it may disable the Automatic Translation feature in order to avoid any extra charging by Google/DeepL. Automatic Translation needs to be manually turned on, after you solve the issues.'=>'Dacă TranslatePress detectează ceva în neregulă la executarea interogărilor în baza de date, poate dezactiva funcția de traducere automată pentru a evita taxarea suplimentară de către Google/DeepL. Traducerea automată trebuie pornită manual, după ce rezolvi problemele.','The SQL errors detected can occur for various reasons including missing tables, missing permissions for the SQL user to create tables or perform other operations, problems after site migration or changes to SQL server configuration.'=>'Erorile SQL detectate pot apărea din diverse motive, inclusiv lipsa tabelelor, lipsa permisiunilor pentru utilizatorul SQL de a crea tabele sau de a efectua alte operațiuni, probleme după migrarea site-ului sau modificări ale configurației serverului SQL.','What you can do in this situation'=>'Ce poți face în această situație','Plan A.'=>'Planul A.','Go to Settings -> TranslatePress -> General tab and Save Settings. This will regenerate the tables using your current SQL settings. Check if no more errors occur while browsing your website in a translated language. Look at the timestamps of the errors to make sure you are not seeing the old errors. Only the most recent 5 errors are displayed.'=>'Mergi la Setări -> TranslatePress -> fila General și salvează setările. Aceasta va regenera tabelele folosind setările SQL actuale. Verifică dacă nu mai apar erori în timp ce navighezi pe site într-o limbă tradusă. Uită-te la data și ora erorilor pentru a te asigura că nu vezi erorile vechi. Se afișează doar cele mai recente 5 erori.','Plan B.'=>'Planul B.','If your problem isn\'t solved, try the following steps:'=>'Dacă problema ta nu este rezolvată, încearcă pașii următori:','Create a backup of your database'=>'Creează o copie de rezervă a bazei de date','Create a copy of each translation table where you encounter errors. You can copy the table within the same database (trp_dictionary_en_us_es_es_COPY for example) -- perform this step only if you want to keep the current translations'=>'Creează o copie a fiecărei tabele de traducere în care întâmpini erori. Poți copia tabela în cadrul aceleiași baze de date (de exemplu, trp_dictionary_en_us_es_es_COPY) -- efectuează acest pas doar dacă vrei să păstrezi traducerile actuale.','Remove the trouble tables by executing the DROP function on them'=>'Elimină tabelele cu probleme executând funcția DROP asupra lor','Go to Settings -> TranslatePress -> General tab and Save Settings. This will regenerate the tables using your current SQL server.'=>'Mergi la Setări -> TranslatePress -> fila General și salvează setările. Aceasta va regenera tabelele folosind serverul tău SQL actual.','Copy the relevant content from the duplicated tables (trp_dictionary_en_us_es_es_COPY for example) in the newly generated table (trp_dictionary_en_us_es_es) -- perform this step only if you want to keep the current translations'=>'Copiază conținutul relevant din tabelele duplicate (de exemplu, trp_dictionary_en_us_es_es_COPY) în tabela nou generată (trp_dictionary_en_us_es_es) -- efectuează acest pas doar dacă vrei să păstrezi traducerile actuale.','Test it to see if everything is working. If something went wrong, you can restore the backup that you\'ve made at the first step. Check if no more errors occur while browsing your website in a translated language. Look at the timestamps of the errors to make sure you are not seeing the old errors. Only the most recent 5 errors are displayed.'=>'Testează pentru a vedea dacă totul funcționează. Dacă ceva nu a mers bine, poți restaura copia de rezervă pe care ai făcut-o la primul pas. Verifică dacă nu mai apar erori în timp ce navighezi pe site într-o limbă tradusă. Uită-te la data și ora erorilor pentru a te asigura că nu vezi erorile vechi. Se afișează doar cele mai recente 5 erori.','Plan C.'=>'Planul C.','If your problem still isn\'t solved, try asking your hosting about your errors. The most common issue is missing permissions for the SQL user, such as the Create Tables permission.'=>'Dacă problema ta încă nu este rezolvată, încearcă să întrebi furnizorul de găzduire despre erorile tale. Cea mai frecventă problemă este lipsa permisiunilor pentru utilizatorul SQL, cum ar fi permisiunea de a crea tabele.','Could not install. Try again from <a href="%s" >Plugins Dashboard.</a>'=>'Nu s-a putut instala. Încearcă din nou din <a href="%s" >Panoul Modulelor.</a>','Active'=>'Activ','Permission denied.'=>'Permisiune refuzată.','Invalid nonce.'=>'Nonce invalid.','Settings scope unknown.'=>'Domeniul setărilor necunoscut.','Legacy disabled.'=>'Legacy dezactivat.','Language Switcher'=>'Selector de limbă','Change language to %s'=>'Schimbă limba în %s','Automatic Translation'=>'Traducere automată','DeepL'=>'DeepL','Unsupported languages'=>'Limbi nesuportate','The selected automatic translation engine does not provide support for these languages.<br>You can still manually translate pages in these languages using the Translation Editor.'=>'Motorul de traducere automată selectat nu oferă suport pentru aceste limbi.<br>Puteți traduce în continuare manual paginile în aceste limbi folosind Editorul de traducere.','API key validation failed.'=>'Validarea cheii API a eșuat.','API key verification was successful.'=>'Verificarea cheii API a reușit.','Please enter your Google Translate key.'=>'Vă rugăm să introduceți cheia Google Translate.','Please enter your DeepL API key.'=>'Vă rugăm să introduceți cheia API DeepL.','Not TranslatePress onboarding page.'=>'Nu este pagina de inițiere TranslatePress.','Step %s does not exist'=>'Pasul %s nu există','Welcome'=>'Bun venit','Add Languages'=>'Adăugare limbi','Enable Addons'=>'Activare suplimente','Finalize'=>'Finalizare','Exit Setup'=>'Ieșire din configurare','Upgrade'=>'Upgrade','Nothing here'=>'Nimic aici','Your <strong>TranslatePress</strong> license is missing or invalid. <br/>Please %1$sregister your copy%2$s to enable automatic website translation via TranslatePress AI, premium addons, automatic updates and support. Need a license key? %3$sPurchase one now%4$s'=>'Licența <strong>TranslatePress</strong> lipsește sau este invalidă. <br/>Vă rugăm să %1$sînregistrați copia%2$s pentru a activa traducerea automată a site-ului web prin TranslatePress AI, addon-urile premium, actualizările automate și asistența. Aveți nevoie de o cheie de licență? %3$sCumpărați una acum%4$s','Your <strong>TranslatePress</strong> license will expire on %1$s. Please %2$sRenew Your Licence%3$s to continue receiving access to automatic translations via TP AI, premium addons, product downloads and automatic updates. %4$sRenew Now%5$s'=>'Licența <strong>TranslatePress</strong> va expira pe %1$s. Vă rugăm să %2$sreînnoiți licența%3$s pentru a continua să primiți acces la traducerile automate prin TP AI, addon-urile premium, descărcările de produse și actualizările automate. %4$sReînnoiți acum%5$s','Error: '=>'Eroare: ','Something went wrong, please try again.'=>'Ceva nu a funcționat corect, vă rugăm să încercați din nou.','Your <strong>TranslatePress</strong> license has expired. <br/>Please %1$sRenew Your Licence%2$s to continue receiving access to automatic translations via TranslatePress AI, premium addons, product downloads, and automatic updates. %3$sRenew now %4$s'=>'Licența <strong>TranslatePress</strong> a expirat. <br/>Vă rugăm să %1$sreînnoiți licența%2$s pentru a continua să primiți acces la traducerile automate prin TranslatePress AI, addon-urile premium, descărcările de produse și actualizările automate. %3$sReînnoiți acum %4$s','License key mismatch. The license you entered doesn’t match the <strong>%1$s</strong> version you have installed. <br/>Please check that you’ve installed the correct version for your license from your %2$sTranslatePress account%3$s.'=>'Cheia de licență nu corespunde. Licența introdusă nu corespunde versiunii <strong>%1$s</strong> pe care o aveți instalată. <br/>Vă rugăm să verificați că ați instalat versiunea corectă pentru licența dumneavoastră din %2$sTranslatePress Account%3$s.','<br/>If you have only the free plugin installed but added a paid license, please install the paid plugin from your TranslatePress account.'=>'<br/>Dacă aveți instalat doar plugin-ul gratuit, dar ați adăugat o licență plătită, vă rugăm să instalați plugin-ul plătit din contul dumneavoastră TranslatePress Account.','You have reached the activation limit for your <strong>%1$s</strong> license. <br/>Manage your active sites from %2$s your account %3$s.'=>'Ați atins limita de activare pentru licența <strong>%1$s</strong>. <br/>Gestionați-vă site-urile active din %2$s contul dumneavoastră %3$s.','Your license is disabled for this URL. Re-enable it from <a target="_blank" href="https://translatepress.com/account/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=license-deactivated">https://translatepress.com/account</a> -> Manage Sites.'=>'Licența dumneavoastră este dezactivată pentru acest URL. Reactivați-o din <a target="_blank" href="https://translatepress.com/account/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=license-deactivated">https://translatepress.com/account</a> -> Gestionare site-uri.','%1$s automatic translation requires an active license. Please %2$srenew%3$s your license or purchase a new one %4$shere%5$s.'=>'Traducerea automată %1$s necesită o licență activă. Vă rugăm să %2$sreînnoiți%3$s licența sau achiziționați una nouă %4$saici%5$s.','Please %1$senter%2$s your license key to enable %3$s automatic translation.'=>'Vă rugăm să %1$sintroduceți%2$s cheia de licență pentru a activa traducerea automată %3$s.','You have less than 5,000 TranslatePress AI words remaining. To continue automatically translating your website, please %spurchase additional AI words at a discount from your account%s.'=>'Mai aveți mai puțin de 5.000 de cuvinte TranslatePress AI rămase. Pentru a continua să traduceți automat site-ul, vă rugăm să %sachiziționați cuvinte AI suplimentare cu reducere din contul dumneavoastră%s.',' Error: '=>' Eroare: ','This website is already activated under a free license. Each website can only use one free license. Please upgrade to a premium plan for more TranslatePress AI words from %1$s your account %2$s.'=>'Acest site web este deja activat sub o licență gratuită. Fiecare site web poate folosi doar o singură licență gratuită. Vă rugăm să faceți upgrade la un plan premium pentru mai multe cuvinte TranslatePress AI din %1$s contul dumneavoastră %2$s.','You do not have a valid license for <strong>TranslatePress</strong>. %1$sGet one for free%2$s to get access to TranslatePress AI.'=>'Nu aveți o licență validă pentru <strong>TranslatePress</strong>. %1$sObțineți una gratuit%2$s pentru a avea acces la TranslatePress AI.','<strong>NEW:</strong> The <strong>Different Domain per Language</strong> add-on is here! Boost your global SEO and create a local experience with country-specific domains like .de or .fr. Upgrade to <a href="https://translatepress.com/pricing/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=new-addon-ddpl-upsell" target="_blank">TranslatePress Business or Developer</a> to access it + more premium perks!'=>'<strong>NOU:</strong> A sosit addon-ul <strong>Different Domain per Language</strong>! Îmbunătățiți-vă SEO-ul global și creați o experiență locală cu domenii specifice țărilor, precum .de sau .fr. Faceți upgrade la <a href="https://translatepress.com/pricing/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=new-addon-ddpl-upsell" target="_blank">TranslatePress Business sau Developer</a> pentru a-l accesa + mai multe beneficii premium!','<strong>NEW:</strong> The <strong>Different Domain per Language</strong> add-on is here! Boost your global SEO and create a local experience with country-specific domains like .de or .fr. <a href="https://translatepress.com/docs/addons/different-domain-per-language/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=new-addon-ddpl" target="_blank">Learn more</a>.'=>'<strong>NOU:</strong> A sosit addon-ul <strong>Different Domain per Language</strong>! Îmbunătățiți-vă SEO-ul global și creați o experiență locală cu domenii specifice țărilor, precum .de sau .fr. <a href="https://translatepress.com/docs/addons/different-domain-per-language/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=new-addon-ddpl" target="_blank">Aflați mai multe</a>.','The daily quota for machine translation characters exceeded. Please check the <strong>TranslatePress -> <a href="%s">Automatic Translation</a></strong> page for more information.'=>'Cota zilnică de caractere pentru traducerea automată a fost depășită. Vă rugăm să verificați pagina <strong>TranslatePress -> <a href="%s">Traducere automată</a></strong> pentru mai multe informații.','Marketing optin'=>'Opt-in pentru marketing','Opt in to our security and feature updates notifications, and non-sensitive diagnostic tracking.'=>'Abonează-te la notificările noastre despre actualizările de securitate și funcționalități, precum și la urmărirea diagnosticelor non-sensibile.','TranslatePress Preferred User Language'=>'Limba preferată a utilizatorului în TranslatePress','Preferred language to navigate the site'=>'Limba preferată pentru navigarea pe site','The language is automatically set based by the last visited language by the user.'=>'Limba este setată automat în funcție de ultima limbă vizitată de utilizator.','Always use this language'=>'Folosește întotdeauna această limbă','By checking this setting the preferred language will remain the one selected above, without the possibility of being changed in the frontend.<br>This language will be used in different operations such as sending email to the user.'=>'Prin bifarea acestei setări, limba preferată va rămâne cea selectată mai sus, fără posibilitatea de a fi schimbată în frontend.<br>Această limbă va fi utilizată în diferite operațiuni, cum ar fi trimiterea de e-mailuri către utilizator.','Hello! Seems like you\'ve been using <strong>TranslatePress</strong> for a while now to translate your website. That\'s awesome! '=>'Salut! Se pare că folosești <strong>TranslatePress</strong> de ceva vreme pentru a-ți traduce site-ul. Minunat! ','If you can spare a few moments to rate it on WordPress.org it would help us a lot (and boost my motivation).'=>'Dacă poți aloca câteva momente pentru a-l evalua pe WordPress.org, ne-ai ajuta foarte mult (și mi-ai crește motivația).','~ Razvan, developer of TranslatePress'=>'~ Răzvan, dezvoltatorul TranslatePress','Rate TranslatePress on WordPress.org plugin page'=>'Evaluează TranslatePress pe pagina pluginului de pe WordPress.org','Ok, I will gladly help!'=>'Da, ajut cu plăcere!','No, thanks.'=>'Nu, mulțumesc.','Full Language Names'=>'Denumiri complete ale limbilor','Short Language Names'=>'Denumiri scurte ale limbilor','Flags with Full Language Names'=>'Steaguri cu denumiri complete ale limbilor','Flags with Short Language Names'=>'Steaguri cu denumiri scurte ale limbilor','Only Flags'=>'Doar steaguri','Full Language Names No HTML'=>'Denumiri complete ale limbilor fără HTML','Bottom Right'=>'Dreapta jos','Bottom Left'=>'Stânga jos','Top Right'=>'Dreapta sus','Top Left'=>'Stânga sus','Dark'=>'Întunecat','Light'=>'Luminos','Deactivate'=>'Dezactivează','Activate'=>'Activează','Invalid language code. Please try again.'=>'Cod de limbă invalid. Te rugăm să încerci din nou.','Language codes can contain only A-Z a-z 0-9 - _ characters. Check your language codes in TranslatePress General Settings.'=>'Codurile de limbă pot conține doar caracterele A-Z a-z 0-9 - _. Verifică codurile de limbă în Setări generale TranslatePress.','Error! Duplicate URL slug values.'=>'Eroare! Valori duplicate ale slug-ului URL.','You cannot select two languages that have the same <a href="https://en.wikipedia.org/wiki/List_of_ISO_639-1_codes" target="_blank">iso code</a> but different formalities because doing so will lead to duplicate <a href="https://developers.google.com/search/docs/specialty/international/localized-versions" target="_blank">hreflang tags</a>.'=>'Nu poți selecta două limbi care au același <a href="https://en.wikipedia.org/wiki/List_of_ISO_639-1_codes" target="_blank">cod ISO</a>, dar formalități diferite, deoarece acest lucru va duce la <a href="https://developers.google.com/search/docs/specialty/international/localized-versions" target="_blank">etichete hreflang</a> duplicate.','Duplicate language detected.<br>Each language can only be added once to ensure accurate translation management.<br> Please change the duplicate language entry and try again. '=>'Limbă duplicată detectată.<br>Fiecare limbă poate fi adăugată o singură dată pentru a asigura o gestionare corectă a traducerilor.<br> Te rugăm să modifici intrarea limbii duplicate și să încerci din nou. ','Current Language'=>'Limba curentă','Opposite Language'=>'Limba opusă','General'=>'General','Translate Site'=>'Tradu site-ul','Addons'=>'Suplimente','License'=>'Licență','Settings'=>'Setări','Activate License'=>'Activează licența','Pro Features'=>'Funcționalități Pro','Need Help?'=>'Nevoie de ajutor?','Recent community discussions'=>'Discuții recente ale comunității','Loading...'=>'Se încarcă...','Unable to load forum posts'=>'Nu s-au putut încărca postările din forum.','Ask a Question'=>'Pune o întrebare','View All Topics'=>'Vezi toate subiectele','by'=>'de','Have a question?'=>'Ai o întrebare?','Get help directly from the plugin developers, suggest improvements, or share your feedback!'=>'Obține ajutor direct de la dezvoltatorii modulului, sugerează îmbunătățiri sau oferă feedback!','Tip for faster help:'=>'Sfat pentru ajutor mai rapid:','Include what you tried, what you expected, and what happened. Screenshots help!'=>'Include ce ai încercat, la ce te așteptai și ce s-a întâmplat. Capturile de ecran ajută!','Toggle support chat'=>'Comută chatul de suport','Ask the community'=>'Întreabă comunitatea','Close'=>'Închide','Empty feed response'=>'Răspuns de flux gol','Unable to parse feed'=>'Nu s-a putut analiza fluxul','Just now'=>'Chiar acum','%d hour ago'=>'%d oră în urmă' . "\0" . '%d ore în urmă' . "\0" . '%d de ore în urmă','%d day ago'=>'%d zi în urmă' . "\0" . '%d zile în urmă' . "\0" . '%d de zile în urmă','Source'=>'Sursă','Srcset'=>'Srcset','Alt attribute'=>'Atribut alt','Title attribute'=>'Atribut title','Anchor link'=>'Ancoră','Placeholder attribute'=>'Atribut placeholder','Submit attribute'=>'Atribut submit','Text'=>'Text','Video Poster'=>'Poster video','plural form'=>'formă de plural','one'=>'unu','few'=>'câteva','many'=>'multe','other'=>'altele','Saved'=>'Salvat','Save'=>'Salvează','Saving translation...'=>'Se salvează traducerea...','You have unsaved changes!'=>'Ai modificări nesalvate!','Discard changes'=>'Renunță la modificări','Discard All'=>'Renunță la toate','Loading Strings...'=>'Se încarcă șirurile...','Select string to translate...'=>'Selectează șirul de tradus...','Close Editor'=>'Închide editorul','From'=>'Din','To'=>'În','Add Media'=>'Adaugă media','Other languages'=>'Alte limbi','Context'=>'Context','View Website As'=>'Vezi site-ul ca','Available in our Pro Versions'=>'Disponibil în versiunile noastre Pro','Select or Upload Media'=>'Selectează sau încarcă media','Use this media'=>'Folosește acest media','Translate'=>'Tradu','Translate entire block element'=>'Tradu întregul element bloc','Split block to translate strings individually'=>'Împarte blocul pentru a traduce șirurile individual','Save changes to translation. Shortcut: CTRL(⌘) + S'=>'Salvează modificările traducerii. Scurtătură: CTRL(⌘) + S','Navigate to next string in dropdown list. Shortcut: CTRL(⌘) + ALT + Right Arrow'=>'Navighează la șirul următor din lista derulantă. Comandă rapidă: CTRL(⌘) + ALT + Săgeată la dreapta','Navigate to previous string in dropdown list. Shortcut: CTRL(⌘) + ALT + Left Arrow'=>'Navighează la șirul anterior din lista derulantă. Comandă rapidă: CTRL(⌘) + ALT + Săgeată la stânga','Discard all changes. Shortcut: CTRL(⌘) + ALT + Z'=>'Renunță la toate modificările. Scurtătură: CTRL(⌘) + ALT + Z','Discard changes to this text box. To discard changes to all text boxes use shortcut: CTRL(⌘) + ALT + Z'=>'Renunță la modificările din această casetă text. Pentru a renunța la modificările din toate casetele text, folosește scurtătura: CTRL(⌘) + ALT + Z','Dismiss tooltip'=>'Închide indicația','Quick Intro'=>'Introducere rapidă','Are you sure you want to split this phrase into smaller parts?'=>'Sigur doriți să împărțiți această frază în părți mai mici?','This string is not ready for translation yet. <br>Try again in a moment...'=>'Acest șir nu este încă pregătit pentru traducere. <br>Încearcă din nou peste un moment...','For this option to work, please update the Browse as other role add-on to the latest version.'=>'Pentru ca această opțiune să funcționeze, actualizați suplimentul Browse as other role la cea mai recentă versiune.','To translate slugs, please update the SEO Pack add-on to the latest version.'=>'Pentru a traduce slug-urile, te rugăm să actualizezi suplimentul SEO Pack la cea mai recentă versiune.','You can add a new language from <a href="%s">Settings->TranslatePress</a>'=>'Puteți adăuga o limbă nouă din <a href="%s">Setări->TranslatePress</a>','However, you can still use TranslatePress to <strong style="background: #f5fb9d;">modify gettext strings</strong> available in your page.'=>'Cu toate acestea, poți folosi în continuare TranslatePress pentru a <strong style="background: #f5fb9d;">modifica șirurile gettext</strong> disponibile în pagina ta.','Strings that are user-created cannot be modified, only those from themes and plugins.'=>'Șirurile create de utilizator nu pot fi modificate, doar cele din teme și pluginuri.','Extra Translation Features'=>'Funcționalități suplimentare de traducere','Support for 130+ Extra Languages'=>'Suport pentru peste 130 de limbi suplimentare','Access to TranslatePress AI'=>'Acces la TranslatePress AI','Translate SEO Title, Description, Slug'=>'Tradu titlul SEO, descrierea și slug-ul','Publish only when translation is complete'=>'Publicare numai după finalizarea traducerii','Translate by Browsing as User Role'=>'Traducere prin navigare ca rol de utilizator','Different Menu Items for each Language'=>'Elemente de meniu diferite pentru fiecare limbă','Automatic User Language Detection'=>'Detectare automată a limbii utilizatorului','Upgrade to PRO'=>'Upgrade la PRO','Upgrade to PRO with our biggest discount of the year!'=>'Upgrade la PRO cu cea mai mare reducere a anului!','This Black Friday, get access to these features and more at a fraction of the costs:'=>'De Black Friday, obțineți acces la aceste funcționalități și multe altele la o fracțiune din costuri:','No available suggestions'=>'Nicio sugestie disponibilă','Suggestions from translation memory'=>'Sugestii din memoria de traducere','Click to Copy'=>'Clic pentru a copia','Human Translation'=>'Traducere umană','Machine Translation'=>'Traducere automată','Text on this page is %s% translated into all languages.'=>'Textul de pe această pagină este tradus în proporție de %s% în toate limbile.','%1$s% of text on this page is translated into %2$s.'=>'%1$s% din textul de pe această pagină este tradus în %2$s.','This page is %1$s% translated into %2$s.'=>'Această pagină este tradusă în proporție de %1$s% în %2$s.','The slug that you are trying to edit is present in other slug types:%s%. Editing it will replace each occurrence, regardless of the current type.'=>'Slug-ul pe care încerci să-l editezi este prezent în alte tipuri de slug: %s. Editarea lui va înlocui fiecare apariție, indiferent de tipul actual.','Hover any text on the page, click %s,<br> then modify the translation in the sidebar.'=>'Plasează cursorul peste orice text de pe pagină, fă clic pe %s,<br> apoi modifică traducerea în bara laterală.','Don\'t forget to Save Translation. Use keyboard shortcut CTRL(⌘) + S'=>'Nu uita să salvezi traducerea. Folosește scurtătura de tastatură CTRL(⌘) + S','Switch language to see the translation changes directly on the page.'=>'Schimbă limba pentru a vedea modificările de traducere direct pe pagină.','Search for any text in this page in the dropdown.'=>'Caută orice text de pe această pagină în lista derulantă.','Your %s license has <span class="trp-license-status-emphasized">expired</span>.'=>'Licența ta %s a <span class="trp-license-status-emphasized">expirat</span>.','Please renew your license to continue receiving access to TranslatePress AI, premium addons, automatic updates and support.'=>'Te rugăm să îți reînnoiești licența pentru a continua să ai acces la TranslatePress AI, suplimente premium, actualizări automate și asistență.','Renew Now'=>'Reînnoiește acum','<strong>This Black Friday, renew your license at a special price</strong> to continue receiving access to product downloads, automatic updates, and support.'=>'<strong>De Black Friday, reînnoiește-ți licența la un preț special</strong> pentru a continua să ai acces la descărcări de produse, actualizări automate și asistență.','Get Deal'=>'Profită de ofertă','Your %s license was <span class="trp-license-status-emphasized">refunded</span>.'=>'Licența ta %s a fost <span class="trp-license-status-emphasized">rambursată</span>.','Please purchase a new license to continue receiving access to TranslatePress AI, premium addons, automatic updates and support.'=>'Te rugăm să cumperi o licență nouă pentru a continua să ai acces la TranslatePress AI, suplimente premium, actualizări automate și asistență.','Purchase a new license'=>'Cumpără o licență nouă','Your %s license is <span class="trp-license-status-emphasized">missing or invalid</span>.'=>'Licența ta %s este <span class="trp-license-status-emphasized">lipsă sau invalidă</span>.','Please enter a valid license to get access to TranslatePress AI, premium addons, automatic updates and support. Need a license key? %1$sPurchase one now%2$s'=>'Te rugăm să introduci o licență validă pentru a avea acces la TranslatePress AI, suplimente premium, actualizări automate și asistență. Ai nevoie de o cheie de licență? %1$sCumpără una acum%2$s','Enter a valid license'=>'Introdu o licență validă','Slugs'=>'Slug-uri','Meta Information'=>'Informații meta','String List'=>'Listă de șiruri','Gettext Strings'=>'Șiruri Gettext','Images'=>'Imagini','Videos'=>'Videoclipuri','Audios'=>'Audio','Dynamically Added Strings'=>'Șiruri adăugate dinamic','Translation Editor'=>'Editor de traduceri','Edit translations by visually selecting them on each site page'=>'Editează traducerile selectându-le vizual pe fiecare pagină a site-ului.','String Translation'=>'Traducere șiruri','Edit url slug translations, plugins and theme translation (emails, forms etc.)'=>'Editează traducerile de slug URL, pluginuri și temă (e-mailuri, formulare etc.)','Current User'=>'Utilizator curent','Logged Out'=>'Deconectat','Translate Page'=>'Traduce pagina','Add a New Language'=>'Adaugă o limbă nouă','Get a Free AI License'=>'Obține o licență AI gratuită','Your License is Invalid'=>'Licența nu este validă','Get More AI Words (%d left)'=>'Obține mai multe cuvinte AI (%d rămase)','Opens post in the translation editor. Post must be saved as draft or published beforehand.'=>'Deschide articolul în editorul de traducere. Articolul trebuie salvat ca schiță sau publicat în prealabil.','Security check'=>'Verificare de securitate','<strong>Warning:</strong> Some strings have possibly incorrectly encoded characters. This may result in breaking the queries, rendering the page untranslated in live mode. Consider revising the following strings or their method of outputting.'=>'<strong>Avertisment:</strong> Unele șiruri conțin caractere posibil codificate incorect. Acest lucru poate cauza erori în interogări, făcând ca pagina să nu fie tradusă în modul live. Luați în considerare revizuirea următoarelor șiruri sau a modului lor de afișare.','TranslatePress data update'=>'Actualizare date TranslatePress','We need to update your translations database to the latest version.'=>'Trebuie să actualizăm baza de date a traducerilor la cea mai recentă versiune.','Updating will allow editing translations of localized text from plugins and theme. Existing translation will still work as expected.'=>'Actualizarea va permite editarea traducerilor de text localizat din module și temă. Traducerea existentă va funcționa în continuare conform așteptărilor.','IMPORTANT: It is strongly recommended to first backup the database!
Are you sure you want to continue?'=>'IMPORTANT: Se recomandă insistent să faci mai întâi o copie de rezervă a bazei de date!
Ești sigur că vrei să continui?','Run the updater'=>'Rulează actualizatorul','Updating will allow editing translations of slugs. Existing translation will still work as expected.'=>'Actualizarea va permite editarea traducerilor de slug-uri. Traducerea existentă va funcționa în continuare conform așteptărilor.','Please activate the SEO Addon from <br/>WordPress -> Settings -> TranslatePress -> Addons section'=>'Te rugăm să activezi suplimentul SEO din <br/>WordPress -> Setări -> TranslatePress -> secțiunea Suplimente','Go to Addons'=>'Mergi la Suplimente','The SEO Pack add-on allows translation of all the URL slugs:'=>'Suplimentul SEO Pack permite traducerea tuturor slug-urilor de URL:','Taxonomy slugs'=>'Slug-uri de taxonomie','Term slugs'=>'Slug-uri de termeni','Post slugs (this includes pages and custom post types)'=>'Slug-uri de articole (aceasta include pagini și tipuri personalizate de conținut)','Post type base slugs'=>'Slug-uri de bază pentru tipuri de conținut','WooCommerce slugs'=>'Slug-uri WooCommerce','The SEO Pack add-on is available with ALL premium versions of the plugin.'=>'Suplimentul SEO Pack este disponibil cu TOATE versiunile premium ale pluginului.','Upgrade to Pro'=>'Upgradează la Pro','Description'=>'Descriere','Article Section'=>'Secțiune articol','Article Tag'=>'Etichetă articol','OG Title'=>'Titlu OG','OG Site Name'=>'Nume site OG','OG Description'=>'Descriere OG','OG Image Alt'=>'Text alternativ imagine OG','Twitter Title'=>'Titlu Twitter','Twitter Description'=>'Descriere Twitter','Twitter Image Alt'=>'Text alternativ imagine Twitter','Page Title'=>'Titlu pagină','Dublin Core Title'=>'Titlu Dublin Core','Dublin Core Description'=>'Descriere Dublin Core','OG Image'=>'Imagine OG','OG Image Secure URL'=>'URL securizat imagine OG','Twitter Image'=>'Imagine Twitter','Removing cdata dictionary strings for language %s...'=>'Se elimină șirurile din dicționarul CDATA pentru limba %s...','Removing untranslated dictionary links for language %s...'=>'Se elimină legăturile de dicționar netraduse pentru limba %s...','Removing duplicated gettext strings for language %s...'=>'Se elimină șirurile Gettext duplicate pentru limba %s...','Removing duplicated dictionary strings for language %s...'=>'Se elimină șirurile duplicate din dicționar pentru limba %s...','Removing untranslated dictionary strings where translation is available for language %s...'=>'Se elimină șirurile netraduse din dicționar pentru care există traducere disponibilă pentru limba %s...','Inserting original strings for language %s...'=>'Se inserează șirurile originale pentru limba %s...','Cleaning original strings table for language %s...'=>'Se curăță tabelul cu șirurile originale pentru limba %s...','Updating original string ids for language %s...'=>'Se actualizează ID-urile șirurilor originale pentru limba %s...','Regenerating original meta table for language %s...'=>'Se regenerează tabelul meta original pentru limba %s...','Cleaning original meta table for language %s...'=>'Se curăță tabelul meta original pentru limba %s...','Replacing original id NULL with value for language %s...'=>'Se înlocuiește ID-ul original NULL cu o valoare pentru limba %s...','Inserting gettext original strings for language %s...'=>'Se inserează șirurile originale Gettext pentru limba %s...','Cleaning gettext original strings table for language %s...'=>'Se curăță tabelul cu șirurile originale Gettext pentru limba %s...','Updating gettext original string ids for language %s...'=>'Se actualizează ID-urile șirurilor originale Gettext pentru limba %s...','Migrating taxonomy and post type base slugs to new table structure...'=>'Se migrează slug-urile de taxonomie și slug-urile de bază ale tipurilor de conținut către noua structură de tabel...','Migrating post slugs to new table structure for language %s...'=>'Se migrează slug-urile de articole către noua structură de tabel pentru limba %s...','Migrating term slugs to new table structure for language %s...'=>'Se migrează slug-urile de termeni la noua structură de tabel pentru limba %s...','Finishing up...'=>'Se finalizează...','Database optimization did not complete successfully. We recommend restoring the original database or <a href="%s" >trying again.</a>'=>'Optimizarea bazei de date nu s-a finalizat cu succes. Vă recomandăm să restaurați baza de date originală sau <a href="%s" >să încercați din nou.</a>','Update aborted! Your user account doesn\'t have the capability to perform database updates.'=>'Actualizare întreruptă! Contul de utilizator nu are capacitatea de a efectua actualizări ale bazei de date.','Update aborted! Invalid nonce.'=>'Actualizare întreruptă! Nonce invalid.','Update aborted! Incorrect action.'=>'Actualizare întreruptă! Acțiune incorectă.','Update aborted! Incorrect language code.'=>'Actualizare abandonată! Cod de limbă incorect.','Updating database to version %s+'=>'Se actualizează baza de date la versiunea %s+','Processing table for language %s...'=>'Se procesează tabelul pentru limba %s...','Back to TranslatePress Settings'=>'Înapoi la setările TranslatePress','Successfully updated database!'=>'Baza de date a fost actualizată cu succes!',' done.'=>' finalizat.','All individual TranslatePress add-on plugins <a href="%1$s" target="_blank">have been discontinued</a> and are now included in the premium Personal, Business and Developer versions of TranslatePress. Please log into your <a href="%2$s" target="_blank">account page</a>, download the new premium version and install it. Your individual addons settings will be ported over.'=>'Toate pluginurile suplimentare individuale TranslatePress <a href="%1$s" target="_blank">au fost retrase</a> și sunt acum incluse în versiunile premium Personal, Business și Developer ale TranslatePress. Vă rugăm să vă autentificați în <a href="%2$s" target="_blank">pagina contului dumneavoastră</a>, să descărcați noua versiune premium și să o instalați. Setările individuale ale suplimentelor dumneavoastră vor fi transferate.','Brand-new Language Switcher Settings are here!'=>'Setările complet noi pentru selectorul de limbă sunt aici!','Explore pre-made templates, switch colors, flag styles, spacing, layouts & more. Use the live preview to perfect your switcher in seconds.'=>'Explorați șabloane predefinite, schimbați culorile, stilurile steagurilor, spațierea, aspectele și multe altele. Folosiți previzualizarea live pentru a perfecționa selectorul în câteva secunde.','Start customizing'=>'Începeți personalizarea','Read documentation'=>'Citiți documentația','TranslatePress'=>'TranslatePress','<strong>TranslatePress</strong> requires <strong><a href="http://php.net/manual/en/book.mbstring.php">Multibyte String PHP library</a></strong>. Please contact your server administrator to install it on your server.'=>'<strong>TranslatePress</strong> necesită <strong><a href="http://php.net/manual/en/book.mbstring.php">biblioteca PHP Multibyte String</a></strong>. Te rugăm să contactezi administratorul serverului pentru a o instala pe serverul tău.','Detected long query limitation on WPEngine hosting. Some large pages may appear untranslated. You can remove limitation by adding the following to your site’s wp-config.php: define( \'WPE_GOVERNOR\', false ); '=>'S-a detectat o limitare a interogărilor lungi pe găzduirea WPEngine. Unele pagini mari pot apărea netraduse. Puteți elimina limitarea adăugând următorul cod în fișierul wp-config.php al site-ului: define( \'WPE_GOVERNOR\', false ); ','Custom Language Flag'=>'Steag de limbă personalizat','The Language code of the added custom language cannot be empty.'=>'Codul de limbă al limbii personalizate adăugate nu poate fi gol.','The Language code of the added custom language is invalid.'=>'Codul de limbă al limbii personalizate adăugate este invalid.','The Automatic Translation Code of the added custom language is invalid.'=>'Codul de traducere automată al limbii personalizate adăugate este invalid.','TranslatePress Add-ons'=>'Suplimente TranslatePress','You must first purchase this version to have access to the addon %1$shere%2$s'=>'Trebuie mai întâi să achiziționați această versiune pentru a avea acces la supliment %1$saici%2$s','Please %1$senter your license%2$s key first, to activate this addon.'=>'Te rugăm să %1$sintroduci cheia de licență%2$s mai întâi pentru a activa acest supliment.','You need an active license to have access to the addon. Renew or purchase a new one %1$shere%2$s.'=>'Ai nevoie de o licență activă pentru a avea acces la supliment. Reînnoiește sau cumpără una nouă %1$saici%2$s.','Advanced Add-ons'=>'Suplimente avansate','These addons extend your translation plugin and are available in the Developer, Business and Personal plans.'=>'Aceste suplimente extind pluginul tău de traducere și sunt disponibile în planurile Developer, Business și Personal.','SEO Pack'=>'SEO Pack','SEO Pack (Legacy)'=>'SEO Pack (Legacy)','SEO support for page slug, page title, description and facebook and twitter social graph information. The HTML lang attribute is properly set.'=>'Suport SEO pentru slug-ul paginii, titlul paginii, descrierea și informațiile de social graph pentru Facebook și Twitter. Atributul HTML lang este setat corect.','Multiple Languages'=>'Mai multe limbi','Add as many languages as you need for your project to go global. Publish your language only when all your translations are done.'=>'Adaugă atâtea limbi câte ai nevoie pentru ca proiectul tău să devină global. Publică limba numai când toate traducerile sunt finalizate.','Pro Add-ons'=>'Suplimente Pro','These addons extend your translation plugin and are available in the Business and Developer plans.'=>'Aceste suplimente extind pluginul tău de traducere și sunt disponibile în planurile Business și Developer.','DeepL Automatic Translation'=>'Traducere automată DeepL','Automatically translate your website through the DeepL API.'=>'Traduce automat site-ul tău prin API-ul DeepL.','Prompts visitors to switch to their preferred language based on their browser settings or IP address and remembers the last visited language.'=>'Invită vizitatorii să treacă la limba preferată pe baza setărilor browserului sau a adresei IP și reține ultima limbă vizitată.','Translator Accounts'=>'Conturi de traducător','Create translator accounts for new users or allow existing users that are not administrators to translate your website.'=>'Creează conturi de traducător pentru utilizatori noi sau permite utilizatorilor existenți care nu sunt administratori să traducă site-ul tău.','Browse As User Role'=>'Navighează ca rol de utilizator','Navigate your website just like a particular user role would. Really useful for dynamic content or hidden content that appears for particular users.'=>'Navighează pe site-ul tău exact așa cum ar face un anumit rol de utilizator. Foarte util pentru conținut dinamic sau conținut ascuns care apare pentru anumiți utilizatori.','Navigation Based on Language'=>'Navigare în funcție de limbă','Configure different menu items for different languages.'=>'Configurează elemente de meniu diferite pentru limbi diferite.','Different Domain per Language'=>'Domeniu diferit pentru fiecare limbă','Connect separate domains or subdomains to each of your translated versions. Strengthen your brand’s local identity and boost SEO performance for every language you support.'=>'Conectează domenii sau subdomenii separate la fiecare dintre versiunile tale traduse. Consolidă identitatea locală a brandului tău și îmbunătățește performanța SEO pentru fiecare limbă pe care o suporti.','Recommended Plugins'=>'Pluginuri recomandate','A short list of plugins you can use to extend your website.'=>'O listă scurtă de pluginuri pe care le poți folosi pentru a-ți extinde site-ul.','Profile Builder'=>'Profile Builder','Capture more user information on the registration form with the help of Profile Builder\'s custom user profile fields and/or add an Email Confirmation process to verify your customers accounts.'=>'Capturează mai multe informații despre utilizatori în formularul de înregistrare cu ajutorul câmpurilor personalizate de profil din Profile Builder și/sau adaugă un proces de confirmare prin e-mail pentru a verifica conturile clienților tăi.','Paid Member Subscriptions'=>'Paid Member Subscriptions','Accept user payments, create subscription plans and restrict content on your membership site.'=>'Acceptă plăți de la utilizatori, creează planuri de abonament și restricționează conținutul pe site-ul tău pentru membri.','WP Webhooks Automator'=>'WP Webhooks Automator','Create no-code automations and workflows on your WordPress site. Easily connect your plugins, sites and apps together.'=>'Creează automatizări și fluxuri de lucru fără cod pe site-ul tău WordPress. Conectează cu ușurință pluginurile, site-urile și aplicațiile tale.','Save Changes'=>'Salvează modificările','TranslatePress Errors'=>'Erori TranslatePress','There are no logged errors.'=>'Nu există erori înregistrate.','Change language'=>'Schimbă limba','Website language selector'=>'Selector de limbă al site-ului','WordPress Translation Plugin'=>'Plugin de traducere WordPress','Available languages'=>'Limbi disponibile','Language Switcher update notice'=>'Notificare de actualizare a selectorului de limbă','Legacy language switcher is currently enabled'=>'Selectorul de limbă vechi este activat în prezent','We’ve upgraded the switcher for richer customization and a better user experience.<br>In order to use the new configurator, turn off <strong>Load legacy language switcher</strong>.'=>'Am actualizat selectorul pentru o personalizare mai bogată și o experiență mai bună a utilizatorului.<br>Pentru a folosi noul configurator, dezactivează <strong>Încarcă selectorul de limbă vechi</strong>.','Note: You can switch back anytime from <strong>Advanced Settings → <a href="%s">Troubleshooting</a></strong>.'=>'Notă: Poți reveni oricând din <strong>Setări avansate → <a href="%s">Depanare</a></strong>.','Enable the new switcher'=>'Activează noul comutator','Your License Key is valid.'=>'Cheia ta de licență este validă.','Your License Key is invalid.'=>'Cheia ta de licență este invalidă.','Your License has expired.'=>'Licența ta a expirat.','Deactivate License'=>'Dezactivează licența','Add a license key'=>'Adaugă o cheie de licență','License Key'=>'Cheie de licență','Manage your license in your %1$s.'=>'Gestionează-ți licența în %1$s.','Account Page'=>'Pagina contului','Don’t have a TranslatePress AI License Key?'=>'Nu ai o cheie de licență TranslatePress AI?','You can get one for %1$sfree%2$s, by creating a free account. It includes:'=>'Poți obține una %1$sgratis%2$s, creând un cont gratuit. Include:','Access to TranslatePress AI for instant automatic translations'=>'Acces la TranslatePress AI pentru traduceri automate instantanee','2000 AI words to translate automatically'=>'2000 de cuvinte AI de tradus automat','Get a free License Today'=>'Obține o licență gratuită astăzi','Debug Information'=>'Informații de depanare','Debug Data for License Checking'=>'Date de depanare pentru verificarea licenței','Debug Data for License Activation'=>'Date de depanare pentru activarea licenței','Get more AI words and unlock all features with TranslatePress Pro.'=>'Obține mai multe cuvinte AI și deblochează toate funcționalitățile cu TranslatePress Pro.','Upgrade now ↗'=>'Actualizează acum ↗','Already purchased a Premium version?'=>'Ai achiziționat deja o versiune Premium?','Go to your %1$s'=>'Mergi la %1$s','TranslatePress.com Account'=>'Cont TranslatePress.com','Download & Install the Pro plugin'=>'Descarcă & instalează modulul Pro','Learn More'=>'Află mai multe','Get a translation volume estimate with a detailed breakdown per page'=>'Obține o estimare a volumului de traducere cu o defalcare detaliată pe pagină','Find how many translatable words are on your website'=>'Află câte cuvinte traductibile există pe site-ul tău','Enable Automatic Translation'=>'Activează traducerea automată','To use <strong>DeepL</strong> for automatic translation, activate this Pro add-on from the <a href="%1$s" target="_self" title="%2$s">%2$s</a>.'=>'Pentru a folosi <strong>DeepL</strong> pentru traducerea automată, activează acest supliment Pro din <a href="%1$s" target="_self" title="%2$s">%2$s</a>.','<strong>DeepL</strong> automatic translation is available as a <a href="%1$s" target="_blank" title="%2$s">%2$s</a>.'=>'Traducerea automată <strong>DeepL</strong> este disponibilă ca <a href="%1$s" target="_blank" title="%2$s">%2$s</a>.','By upgrading you\'ll get access to all paid add-ons, premium support and help fund the future development of TranslatePress.'=>'Prin upgrade vei avea acces la toate suplimentele plătite, suport premium și vei ajuta la finanțarea dezvoltării viitoare a TranslatePress.','Please note that DeepL API usage is paid separately. See <a href="https://www.deepl.com/pro.html#developer">DeepL pricing information</a>.'=>'Te rugăm să reții că utilizarea API DeepL se plătește separat. Vezi <a href="https://www.deepl.com/pro.html#developer">informații despre prețuri DeepL</a>.','TranslatePress Pro Add-ons'=>'Suplimente TranslatePress Pro','Test API credentials'=>'Testează datele de autentificare API','Check if the selected translation engine is configured correctly.'=>'Verifică dacă motorul de traducere selectat este configurat corect.','Alternative Engines'=>'Motoare alternative','Switch to TranslatePress AI'=>'Comută la TranslatePress AI','Integrate machine translation directly with your WordPress website.'=>'Integrează traducerea automată direct cu site-ul tău WordPress.','More info'=>'Mai multe informații','Choose which engine you want to use in order to %1$s automatically translate your website.'=>'Alege motorul pe care vrei să îl folosești pentru a %1$s traduce automat site-ul tău.','Automatic Translation Settings'=>'Setări traducere automată','AI Words Low Notification'=>'Notificare număr scăzut de cuvinte AI','Receive an email notification when your TranslatePress AI word count drops below the specified threshold.'=>'Primești o notificare prin email când numărul de cuvinte TranslatePress AI scade sub pragul specificat.','This feature is only available when using the TranslatePress AI translation engine.'=>'Această funcționalitate este disponibilă doar la utilizarea motorului de traducere TranslatePress AI.','Notification Email'=>'Email de notificare','The email address where the low AI words notification will be sent.'=>'Adresa de email la care va fi trimisă notificarea privind numărul scăzut de cuvinte AI.','Word Threshold'=>'Prag de cuvinte','words'=>'cuvinte','You will be notified when remaining AI words drop below this number.'=>'Vei fi notificat când numărul de cuvinte AI rămase scade sub acest număr.','Automatically Translate Slugs'=>'Traducere automată a slug-urilor','Generate automatic translations of slugs for posts, pages and Custom Post Types.<br/>The slugs will be automatically translated starting with the second refresh of each page.'=>'Generează traduceri automate ale slug-urilor pentru articole, pagini și tipuri personalizate de conținut.<br/>Slug-urile vor fi traduse automat începând cu a doua reîmprospătare a fiecărei pagini.','This feature is only available in the paid version. Upgrade TranslatePress and unlock more premium features.'=>'Această funcționalitate este disponibilă doar în versiunea plătită. Fă upgrade la TranslatePress și deblochează mai multe funcționalități premium.','Requires <a href="%s" title="TranslatePress Add-on SEO Pack documentation" target="_blank">SEO Pack Add-on</a> to be installed and activated.'=>'Necesită ca <a href="%s" title="TranslatePress Add-on SEO Pack documentation" target="_blank">suplimentul SEO Pack</a> să fie instalat și activat.','Upgrade now'=>'Fă upgrade acum','Block Crawlers'=>'Blocare crawlere','Block crawlers from triggering automatic translations on your website.<br>This will not prevent crawlers from accessing this site\'s pages.'=>'Împiedică crawlerele să declanșeze traduceri automate pe site-ul tău.<br>Aceasta nu va împiedica crawlerele să acceseze paginile site-ului.','Limit machine translation / characters per day'=>'Limitează traducerea automată / caractere pe zi','Add a limit to the number of automatically translated characters so you can better budget your project.'=>'Adaugă o limită la numărul de caractere traduse automat pentru a-ți putea gestiona mai bine bugetul proiectului.','characters per day'=>'caractere pe zi','Today\'s Character Count: '=>'Numărul de caractere de astăzi: ','Log machine translation queries.'=>'Înregistrează interogările de traducere automată.','Only enable for testing purposes. Can impact performance.<br>All records are stored in the wp_trp_machine_translation_log database table. Use a plugin like <a href="https://wordpress.org/plugins/wp-data-access/" target="_blank">WP Data Access</a> to browse the logs or directly from your database manager (PHPMyAdmin, etc.)'=>'Activează doar în scopuri de testare. Poate afecta performanța.<br>Toate înregistrările sunt stocate în tabela de baze de date wp_trp_machine_translation_log. Folosește un plugin precum <a href="https://wordpress.org/plugins/wp-data-access/" target="_blank">WP Data Access</a> pentru a naviga în jurnale sau direct din managerul tău de baze de date (PHPMyAdmin, etc.)','Test API Credentials'=>'Testează credențialele API','HTTP Referrer: '=>'HTTP Referrer: ','Use this HTTP Referrer if the API lets you restrict key usage from its Dashboard.'=>'Folosește acest HTTP Referrer dacă API-ul îți permite să restricționezi utilizarea cheii din Panoul său de control.','Response'=>'Răspuns','Response Body'=>'Corpul răspunsului','Entire Response From wp_remote_get():'=>'Răspunsul complet de la wp_remote_get():','All Languages'=>'Toate limbile','Select the languages you wish to make your website available in.'=>'Selectează limbile în care dorești să faci site-ul tău disponibil.','Formality'=>'Formalitate','Code'=>'Cod','Slug'=>'Slug','Default'=>'Implicit','Formal'=>'Formal','Informal'=>'Informal','Language'=>'Limbă','This language does not support formality. '=>'Această limbă nu suportă formalitatea. ','Are you sure you want to remove this language?'=>'Sigur dorești să elimini această limbă?','Custom Languages'=>'Limbi personalizate','To Add more languages activate the Multiple Languages Addon'=>'Pentru a adăuga mai multe limbi, activează Multiple Languages Addon','You need an active license to add more languages. Verify in your %1$saccount%2$s that your license is valid'=>'Ai nevoie de o licență activă pentru a adăuga mai multe limbi. Verifică în %1$scontul tău%2$s că licența este validă','Please %1$senter your license%2$s key first to add more languages.'=>'Te rugăm să %1$sintrodu cheia%2$s de licență mai întâi pentru a adăuga mai multe limbi.','Adding more than two languages is a paid feature. Upgrade TranslatePress and unlock more premium features.'=>'Adăugarea a mai mult de două limbi este o funcționalitate plătită. Fă upgrade la TranslatePress și deblochează mai multe funcționalități premium.','Website Languages'=>'Limbile site-ului','Default Language'=>'Limba implicită','Select the language your content is written in.'=>'Selectează limba în care este scris conținutul.','WARNING. Changing the default language will invalidate existing translations.'=>'AVERTISMENT. Schimbarea limbii implicite va invalida traducerile existente.','Even changing from en_US to en_GB, because they are treated as two different languages.'=>'Chiar și schimbarea de la en_US la en_GB, deoarece sunt tratate ca două limbi diferite.','In most cases changing the default flag is all it is needed: '=>'În majoritatea cazurilor, schimbarea steagului implicit este tot ce este necesar: ','replace the default flag'=>'înlocuiește steagul implicit','Re-run Setup Wizard'=>'Rulează din nou expertul de configurare','The Setup wizard allows you to quickly setup TranslatePress. You can initiate it at any time.'=>'Expertul de configurare îți permite să configurezi rapid TranslatePress. Îl poți iniția în orice moment.','Language Settings'=>'Setări limbă','Use Native language name'=>'Folosește denumirea nativă a limbii','Check if you want to display languages in their native names. Otherwise, languages will be displayed in English.'=>'Bifează dacă vrei să afișezi limbile în denumirile lor native. În caz contrar, limbile vor fi afișate în engleză.','Use a subdirectory for the default language'=>'Folosește un subdirector pentru limba implicită','Check if you want to add the subdirectory in the URL for the default language.</br>By checking this option, the default language seen by website visitors will become the first one in the "All Languages" list.'=>'Bifează dacă vrei să adaugi subdirectorul în URL pentru limba implicită.<br/>Prin bifarea acestei opțiuni, limba implicită văzută de vizitatorii site-ului va deveni prima din lista „Toate limbile”.','Force language in custom links'=>'Forțează limba în linkurile personalizate','Select Yes if you want to force custom links without language encoding to keep the currently selected language.'=>'Selectează Da dacă vrei să forțezi linkurile personalizate fără codificare de limbă să păstreze limba selectată momentan.','Shortcode '=>'Shortcode ','Use shortcode on any page or widget.'=>'Folosește shortcode pe orice pagină sau widget.','You can also add the <a href="%s" title="Language Switcher Block Documentation">Language Switcher Block</a> in the WP Gutenberg Editor.'=>'Poți adăuga și <a href="%s" title="Language Switcher Block Documentation">Blocul de comutare a limbii</a> în editorul WP Gutenberg.','Menu item'=>'Element de meniu','Go to  %1$s Appearance -> Menus%2$s to add languages to the Language Switcher in any menu.'=>'Mergi la  %1$s Aspect -> Meniuri%2$s pentru a adăuga limbi în selectorul de limbă din orice meniu.','Learn more in our documentation.'=>'Află mai multe în documentația noastră.','Floating language selection'=>'Selector de limbă plutitor','Add a floating dropdown that follows the user on every page.'=>'Adaugă o listă derulantă plutitoare care însoțește utilizatorul pe fiecare pagină.','Show "Powered by TranslatePress"'=>'Afișează "Propulsat de TranslatePress"','Show the small "Powered by TranslatePress" label in the floater language switcher.'=>'Afișează eticheta mică "Propulsat de TranslatePress" în selectorul de limbă plutitor.','5 Days to Better Multilingual Websites'=>'5 zile pentru site-uri web multilingve mai bune','%sJoin our FREE & EXCLUSIVE onboarding course%s and learn how to grow your multilingual traffic, reach international markets, and save time & money while getting the most out of TranslatePress!'=>'%sAlătură-te cursului nostru GRATUIT și EXCLUSIV de integrare%s și află cum să-ți crești traficul multilingv, să ajungi pe piețe internaționale și să economisești timp și bani, profitând la maximum de TranslatePress!','Invalid email address'=>'Adresă de email invalidă','Your email'=>'Emailul tău','Sign me up!'=>'Înscrie-mă!','Sign up with your email address and receive a 5-part email guide to help you maximize the power of TranslatePress.'=>'Înscrie-te cu adresa ta de email și primește un ghid în 5 părți prin email care te ajută să profiți la maximum de TranslatePress.','Dismiss email course notification'=>'Înlătură notificarea cursului prin email','Hey %s,<br>Never miss an important update - opt in to our security and feature updates notifications, and non-sensitive diagnostic tracking.'=>'Hei %s,<br>Nu rata nicio actualizare importantă – optează pentru notificările despre actualizările de securitate și funcționalități și pentru monitorizarea diagnosticelor non-sensibile.','Allow & Continue'=>'Permite și continuă','Skip'=>'Sari peste','This will allow TranslatePress to:'=>'Acest lucru îi va permite TranslatePress să:','Your profile overview'=>'Prezentarea generală a profilului','Name and email address'=>'Numele și adresa de e-mail','Admin Notices'=>'Notificări administrative','Updates, announcements, marketing, no spam'=>'Actualizări, anunțuri, marketing, fără spam','Plugin status & settings'=>'Starea și setările modulului','Active, Deactivated, installed version and settings'=>'Activ, dezactivat, versiunea instalată și setările','Privacy Policy'=>'Politica de confidențialitate','Terms of Service'=>'Termeni și condiții','Support'=>'Asistență','Documentation'=>'Documentație','Add Extra AI Words'=>'Adaugă cuvinte AI suplimentare','Optimize TranslatePress database tables'=>'Optimizează tabelele bazei de date TranslatePress','<strong>IMPORTANT NOTE:</strong> Before performing this action it is strongly recommended to first backup the database.'=>'<strong>NOTĂ IMPORTANTĂ:</strong> Înainte de a efectua această acțiune, se recomandă insistent să faceți mai întâi o copie de rezervă a bazei de date.','IMPORTANT: It is strongly recommended to first backup the database!! Are you sure you want to continue?'=>'IMPORTANT: Se recomandă insistent să faceți mai întâi o copie de rezervă a bazei de date!! Sigur doriți să continuați?','Operations to perform'=>'Operații de efectuat','Remove CDATA for original and dictionary strings'=>'Elimină CDATA pentru șirurile originale și cele din dicționar','Removes CDATA from trp_original_strings and trp_dictionary_* tables.<br>This type of content should not be detected by TranslatePress. It might have been introduced in the database in older versions of the plugin.'=>'Elimină CDATA din tabelele trp_original_strings și trp_dictionary_*.<br>Acest tip de conținut nu ar trebui detectat de TranslatePress. Ar fi putut fi introdus în baza de date în versiuni mai vechi ale modulului.','Remove untranslated links from dictionary tables'=>'Elimină linkurile netraduse din tabelele dicționarului','Removes untranslated links and images from all trp_dictionary_* tables. These tables contain translations for user-inputted strings such as post content, post title, menus etc.'=>'Elimină linkurile și imaginile netraduse din toate tabelele trp_dictionary_*. Aceste tabele conțin traduceri pentru șirurile introduse de utilizator, cum ar fi conținutul articolului, titlul articolului, meniurile etc.','Remove duplicate rows for gettext strings'=>'Elimină rândurile duplicate pentru șirurile Gettext','Cleans up all trp_gettext_* tables of duplicate rows. These tables contain translations for themes and plugin strings.'=>'Curăță toate tabelele trp_gettext_* de rândurile duplicate. Aceste tabele conțin traduceri pentru șirurile din teme și pluginuri.','Remove duplicate rows for dictionary strings'=>'Elimină rândurile duplicate pentru șirurile din dicționar','Cleans up all trp_dictionary_* tables of duplicate rows. These tables contain translations for user-inputted strings such as post content, post title, menus etc.'=>'Curăță toate tabelele trp_dictionary_* de rândurile duplicate. Aceste tabele conțin traduceri pentru șirurile introduse de utilizator, cum ar fi conținutul articolului, titlul articolului, meniurile etc.','Remove duplicate rows for original dictionary strings'=>'Elimină rândurile duplicate pentru șirurile originale din dicționar','Cleans up all trp_original_strings table of duplicate rows. This table contains strings in the default language, without any translation.<br>The trp_original_meta table, which contains meta information that refers to the post parent’s ID, is also regenerated.<br>Such duplicates can appear in exceptional situations of unexpected behavior.'=>'Curăță tabelul trp_original_strings de rândurile duplicate. Acest tabel conține șiruri în limba implicită, fără nicio traducere.<br>Tabelul trp_original_meta, care conține informații meta care fac referire la ID-ul articolului părinte, este de asemenea regenerat.<br>Astfel de duplicate pot apărea în situații excepționale de comportament neașteptat.','Replace gettext strings that have original ID NULL with the correct original IDs'=>'Înlocuiește șirurile Gettext care au ID-ul original NULL cu ID-urile originale corecte','Fixes an edge case issue where some gettext strings have the original ID incorrectly set to NULL, causing problems in the Translation Editor.<br>This operation corrects the original IDs in the trp_gettext_* tables.<br>Only check this option if you encountered an issue in the Translation Editor where clicking the green pencil did not bring up the gettext string for translation in the left sidebar.<br>Otherwise, please leave this option unchecked because it\'s an intensive operation.'=>'Corectează o problemă de caz particular în care unele șiruri Gettext au ID-ul original setat incorect la NULL, cauzând probleme în Editorul de Traduceri.<br>Această operațiune corectează ID-urile originale din tabelele trp_gettext_*.<br>Bifează această opțiune doar dacă ai întâmpinat o problemă în Editorul de Traduceri unde apăsarea pe creionul verde nu afișa șirul Gettext pentru traducere în bara laterală stângă.<br>În caz contrar, te rugăm să lași această opțiune debifată deoarece este o operațiune intensivă.','Optimize Database'=>'Optimizează baza de date','TranslatePress Database Updater'=>'TranslatePress Database Updater','Updating TranslatePress tables. Please leave this window open.'=>'Se actualizează tabelele TranslatePress. Vă rugăm să lăsați această fereastră deschisă.','The inactive languages will still be visible and active for the admin. For other users they won\'t be visible in the language switchers and won\'t be accessible either.'=>'Limbile inactive vor fi în continuare vizibile și active pentru administrator. Pentru ceilalți utilizatori, nu vor fi vizibile în selectoarele de limbă și nici nu vor fi accesibile.','unknown'=>'necunoscut','<strong>Extra Languages add-on</strong> requires TranslatePress version %1$s or higher. You are currently using version %2$s. Please update TranslatePress to enable this feature.'=>'<strong>Suplimentul Extra Languages</strong> necesită versiunea %1$s sau o versiune mai recentă de TranslatePress. Utilizați în prezent versiunea %2$s. Vă rugăm să actualizați TranslatePress pentru a activa această funcționalitate.','Automatic and manual slug translation changes performed when <strong>TranslatePress - Multilingual</strong> 2.8.4 was active had to be removed because of some issues with that version. All slug translations from before that version are now in use. Thank you for understanding!'=>'Modificările automate și manuale de traducere a slug-urilor efectuate când <strong>TranslatePress - Multilingual</strong> 2.8.4 era activă au trebuit eliminate din cauza unor probleme cu acea versiune. Toate traducerile de slug-uri de dinaintea acelei versiuni sunt acum în uz. Îți mulțumim pentru înțelegere!','If you absolutely need them, the removed translations can be found in tables trp_slug_original_obsolete and trp_slug_translation_obsolete.'=>'Dacă aveți neapărată nevoie de ele, traducerile eliminate pot fi găsite în tabelele trp_slug_original_obsolete și trp_slug_translation_obsolete.','View Docs'=>'Vizualizează documentația','Assign different domains or subdomains to each language. When visitors access these domains, TranslatePress loads the appropriate language translation directly without redirecting.'=>'Atribuie domenii sau subdomenii diferite fiecărei limbi. Când vizitatorii accesează aceste domenii, TranslatePress încarcă direct traducerea corespunzătoare fără redirecționare.','Example: %1$s for English, %2$s for Spanish, %3$s for French.'=>'Exemplu: %1$s pentru engleză, %2$s pentru spaniolă, %3$s pentru franceză.','Before enabling:'=>'Înainte de activare:','Ensure your domains are registered, pointed to your server, and have SSL certificates configured.'=>'Asigură-te că domeniile tale sunt înregistrate, indicate către serverul tău și au certificate SSL configurate.','Domain'=>'Domeniu','Map this language to a different domain or sub-domain.'=>'Asociază această limbă cu un alt domeniu sau subdomeniu.','https://example.com'=>'https://example.com','Prefill with current domain'=>'Precompletează cu domeniul actual','Check DNS'=>'Verifică DNS','Checking DNS...'=>'Se verifică DNS...','DNS is correctly configured!'=>'DNS este configurat corect!','DNS check failed. Please verify your domain configuration.'=>'Verificarea DNS a eșuat. Te rugăm să verifici configurația domeniului.','This domain is already assigned to another language.'=>'Acest domeniu este deja atribuit altei limbi.','<strong>Different Domain per Language add-on</strong> requires TranslatePress version %1$s or higher. You are currently using version %2$s. Please update TranslatePress to enable this feature.'=>'<strong>Suplimentul Different Domain per Language</strong> necesită TranslatePress versiunea %1$s sau mai nouă. În prezent folosești versiunea %2$s. Te rugăm să actualizezi TranslatePress pentru a activa această funcționalitate.','Note: This option is disabled when Different Domain for Language addon is active.'=>'Notă: Această opțiune este dezactivată când suplimentul Different Domain for Language este activ.','Different Domain per Language: Domain is required when domain mapping is enabled. The toggle has been disabled for languages with empty domains.'=>'Different Domain per Language: Domeniul este obligatoriu când maparea domeniilor este activată. Comutatorul a fost dezactivat pentru limbile cu domenii necompletate.','Different Domain per Language: The same domain cannot be assigned to multiple languages. The toggle has been disabled for duplicate domains.'=>'Different Domain per Language: Același domeniu nu poate fi atribuit mai multor limbi. Comutatorul a fost dezactivat pentru domeniile duplicate.','Different Domain per Language: A language domain cannot be the same as the main site URL. The toggle has been disabled for the matching domain.'=>'Different Domain per Language: Domeniul unei limbi nu poate fi identic cu URL-ul principal al site-ului. Comutatorul a fost dezactivat pentru domeniul corespunzător.','Please enter a domain.'=>'Te rugăm să introduci un domeniu.','Invalid domain format.'=>'Format de domeniu nevalid.','Could not reach domain: %s'=>'Nu s-a putut accesa domeniul: %s','Domain returned HTTP status %d.'=>'Domeniul a returnat statusul HTTP %d.','Domain is reachable!'=>'Domeniul este accesibil!','Limit this menu item to the following languages'=>'Limitează acest element de meniu la următoarele limbi','Date format'=>'Format dată','Customize the date formatting per each translated language.<br/>Leave empty for default WP setting or see more information <a href="https://wordpress.org/support/article/formatting-date-and-time/" title="Formatting Date and Time" target="_blank">here</a>'=>'Personalizează formatarea datei pentru fiecare limbă tradusă.<br/>Lăsați gol pentru setarea implicită WP sau consultați mai multe informații <a href="https://wordpress.org/support/article/formatting-date-and-time/" title="Formatting Date and Time" target="_blank">aici</a>','To edit an existing TranslatePress language, input the language code and fill in only the columns you want to overwrite (e.g. Language name, Flag).<br>You can also add new custom languages. They will be available under General settings, All Languages list, where the URL slug can be edited.'=>'Pentru a edita o limbă TranslatePress existentă, introdu codul limbii și completează doar coloanele pe care vrei să le suprascrii (de ex. Numele limbii, Steagul).<br>Poți adăuga, de asemenea, limbi personalizate noi. Acestea vor fi disponibile în Setări generale, lista tuturor limbilor, unde poate fi editat slug-ul URL.','For custom flag, first upload the image in media library then paste the URL.<br>Changing or deleting a custom language will impact translations and site URL\'s.<br>The Language code and the ISO Code should contain only alphabetical values, numerical values, "-" and "_".<br>The ISO Codes can be found on <a href = "https://cloud.google.com/translate/docs/languages" target = "_blank">Google ISO Codes</a> and <a href = "https://www.deepl.com/docs-api/translating-text/" target = "_blank">DeepL Target Codes</a>.'=>'Pentru steag personalizat, încărcați mai întâi imaginea în biblioteca media, apoi lipiți URL-ul.<br>Modificarea sau ștergerea unei limbi personalizate va afecta traducerile și URL-urile site-ului.<br>Codul limbii și codul ISO trebuie să conțină doar valori alfabetice, valori numerice, "-" și "_".<br>Codurile ISO pot fi găsite pe <a href = "https://cloud.google.com/translate/docs/languages" target = "_blank">Coduri ISO Google</a> și <a href = "https://www.deepl.com/docs-api/translating-text/" target = "_blank">Coduri țintă DeepL</a>.','Language code'=>'Cod limbă','Language name'=>'Nume limbă','Native name'=>'Nume nativ','ISO Code'=>'Cod ISO','Flag URL'=>'URL steag','Text RTL'=>'Text RTL','Custom language'=>'Limbă personalizată','Disable dynamic translation'=>'Dezactivează traducerea dinamică','It disables detection of strings displayed dynamically using JavaScript. <br/>Strings loaded via a server side AJAX call will still be translated.'=>'Dezactivează detectarea șirurilor afișate dinamic folosind JavaScript. <br/>Șirurile încărcate printr-un apel AJAX la nivel de server vor fi în continuare traduse.','Disable translation for gettext strings'=>'Dezactivează traducerea pentru șirurile Gettext','Gettext Strings are strings outputted by themes and plugins. <br> Translating these types of strings through TranslatePress can be unnecessary if they are already translated using the .po/.mo translation file system.<br>Enabling this option can improve the page load performance of your site in certain cases. The disadvantage is that you can no longer edit gettext translations using TranslatePress, nor benefit from automatic translation on these strings.'=>'Șirurile Gettext sunt șiruri generate de teme și pluginuri. <br> Traducerea acestor tipuri de șiruri prin TranslatePress poate fi inutilă dacă sunt deja traduse folosind sistemul de fișiere de traducere .po/.mo. <br>Activarea acestei opțiuni poate îmbunătăți performanța de încărcare a paginii site-ului tău în anumite cazuri. Dezavantajul este că nu mai poți edita traducerile Gettext folosind TranslatePress și nici nu poți beneficia de traducerea automată pentru aceste șiruri.','Gettext Strings translation is disabled'=>'Traducerea șirurilor Gettext este dezactivată','To enable it go to '=>'Pentru a o activa, mergeți la ','TranslatePress->Advanced Settings->Debug->Disable translation for gettext strings'=>'TranslatePress->Setări avansate->Depanare->Dezactivează traducerea pentru șiruri gettext',' and uncheck the Checkbox.'=>' și debifați caseta de selectare.','Dismiss'=>'Respinge','Exclude translated links from sitemap'=>'Exclude link-urile traduse din sitemap','Do not include translated links in sitemaps generated by SEO plugins.<br/>Requires <a href="https://translatepress.com/docs/addons/seo-pack/?utm_source=tp-advanced&utm_medium=client-site&utm_campaign=miscellaneous" title="TranslatePress Add-on SEO Pack documentation" target="_blank"> SEO Pack Add-on</a> to be installed and activated.'=>'Nu include linkurile traduse în sitemaps generate de pluginurile SEO.<br/>Necesită ca <a href="https://translatepress.com/docs/addons/seo-pack/?utm_source=tp-advanced&utm_medium=client-site&utm_campaign=miscellaneous" title="TranslatePress Add-on SEO Pack documentation" target="_blank"> suplimentul SEO Pack</a> să fie instalat și activat.','Disable post container tags for post title'=>'Dezactivează tagurile container pentru titlul articolului','It disables search indexing the post title in translated languages.<br/>Useful when the title of the post doesn\'t allow HTML thus breaking the page.'=>'Dezactivează indexarea în căutare a titlului articolului în limbile traduse.<br/>Util atunci când titlul articolului nu acceptă HTML, provocând erori în pagină.','Disable post container tags for post content'=>'Dezactivează tagurile container pentru conținutul articolului','It disables search indexing the post content in translated languages.<br/>Useful when the content of the post doesn\'t allow HTML thus breaking the page.'=>'Dezactivează indexarea în căutare a conținutului articolului în limbile traduse.<br/>Util atunci când conținutul articolului nu acceptă HTML, provocând erori în pagină.','Do not translate certain paths'=>'Nu traduce anumite căi','Choose what paths can be translated. Supports wildcard at the end of the path.<br>For example, to exclude https://example.com/some/path you can either use the rule /some/path/ or /some/*.<br>Enter each rule on it\'s own line. To exclude the home page use {{home}}.'=>'Alege ce căi pot fi traduse. Acceptă wildcard la sfârșitul căii.<br>De exemplu, pentru a exclude https://example.com/some/path poți folosi fie regula /some/path/, fie /some/*.<br>Introdu fiecare regulă pe propria sa linie. Pentru a exclude pagina principală, folosește {home}.','Exclude Paths From Translation'=>'Exclude căile din traducere','Translate Only Certain Paths'=>'Traduce doar anumite căi','Enable the hreflang x-default tag for language:'=>'Activează eticheta hreflang x-default pentru limba:','Enables the hreflang="x-default" for an entire language. See documentation for more details.'=>'Activează hreflang="x-default" pentru o întreagă limbă. Consultă documentația pentru mai multe detalii.','Translate numbers and numerals'=>'Traduce numere și cifre','Enable translation of numbers ( e.g. phone numbers)'=>'Activează traducerea numerelor (ex. numere de telefon)','Selector'=>'Selector','Exclude from dynamic translation'=>'Exclude din traducerea dinamică','Do not dynamically translate strings that are found in html nodes matching these selectors.<br>Excludes all the children of HTML nodes matching these selectors from being translated using JavaScript.<br/>These strings will still be translated on the server side if possible.'=>'Nu traduce dinamic șirurile care se găsesc în nodurile HTML ce corespund acestor selectori.<br>Exclude toți copiii nodurilor HTML ce corespund acestor selectori de la traducerea prin JavaScript.<br/>Aceste șiruri vor fi traduse în continuare pe partea de server, dacă este posibil.','Gettext String'=>'Șir Gettext','Exclude Gettext Strings'=>'Exclude șirurile Gettext','Exclude these strings from being translated as Gettext strings by TranslatePress. Leave the domain empty to take into account any Gettext string.<br/>Can still be translated through po/mo files.'=>'Exclude aceste șiruri de la traducerea ca șiruri Gettext de către TranslatePress. Lasă domeniul gol pentru a lua în considerare orice șir Gettext.<br/>Pot fi în continuare traduse prin fișiere po/mo.','Exclude selectors only from automatic translation'=>'Exclude selectorii doar din traducerea automată','Do not automatically translate strings that are found in html nodes matching these selectors.<br>Excludes all the children of HTML nodes matching these selectors from being automatically translated.<br>Manual translation of these strings is still possible.'=>'Nu traduce automat șirurile care se găsesc în nodurile HTML ce corespund acestor selectori.<br>Exclude toți copiii nodurilor HTML ce corespund acestor selectori de la traducerea automată.<br>Traducerea manuală a acestor șiruri este încă posibilă.','Exclude selectors from translation'=>'Exclude selectorii din traducere','Do not translate strings that are found in html nodes matching these selectors.<br>Excludes all the children of HTML nodes matching these selectors from being translated.<br>These strings cannot be translated manually nor automatically.'=>'Nu traduce șirurile care se găsesc în nodurile HTML ce corespund acestor selectori.<br>Exclude toți copiii nodurilor HTML ce corespund acestor selectori de la traducere.<br>Aceste șiruri nu pot fi traduse manual nici automat.','String'=>'Șir','Exclude strings from automatic translation'=>'Exclude șirurile de la traducerea automată','Do not automatically translate these strings (ex. names, technical words...)<br>Paragraphs containing these strings will still be translated except for the specified part.'=>'Nu traduce automat aceste șiruri (ex. nume, cuvinte tehnice...)<br>Paragrafele care conțin aceste șiruri vor fi în continuare traduse, cu excepția părții specificate.','Fix broken HTML'=>'Repară HTML-ul stricat','General attempt to fix broken or missing HTML on translated pages.<br/>'=>'Încercare generală de a repara HTML-ul stricat sau lipsă de pe paginile traduse.<br/>','Force slash at end of home url:'=>'Forțează slash la sfârșitul URL-ului principal:','Ads a slash at the end of the home_url() function'=>'Adaugă un slash la sfârșitul funcției home_url()','Show Both (recommended)'=>'Afișează ambele (recomandat)','Remove Country Locale'=>'Elimină localizarea țării','Remove Region Independent Locale'=>'Elimină localizarea independentă de regiune','Remove duplicate hreflang'=>'Elimină hreflang-ul duplicat','Choose which hreflang tags will appear on your website.<br/>We recommend showing both types of hreflang tags as indicated by <a href="https://developers.google.com/search/docs/advanced/crawling/localized-versions" title="Google Crawling" target="_blank">Google documentation</a>.<br/>Removing Country Locale when having multiple Country Locales of the same language (ex. English UK and English US) will result in showing one hreflang tag with link to just one of the region locales for that language.'=>'Alege ce taguri hreflang vor apărea pe site-ul tău.<br/>Recomandăm afișarea ambelor tipuri de taguri hreflang, așa cum indică <a href="https://developers.google.com/search/docs/advanced/crawling/localized-versions" title="Google Crawling" target="_blank">documentația Google</a>.<br/>Eliminarea Localizării de țară atunci când există mai multe Localizări de țară ale aceleiași limbi (ex. English UK și English US) va avea ca rezultat afișarea unui tag hreflang cu legătură doar la una dintre localizările regionale pentru acea limbă.','Default (example: en-US, fr-CA, etc.)'=>'Implicit (exemplu: en-US, fr-CA, etc.)','Regional (example: en, fr, es, etc.)'=>'Regional (exemplu: en, fr, es, etc.)','HTML Lang Attribute Format'=>'Formatul atributului HTML lang','Change lang attribute of the html tag to a format that includes country regional or not. <br>In HTML, the lang attribute (<html lang="en-US">)  should be used to  specify the language of text content so that the  browser can correctly display or process  your content (eg. for  hyphenation, styling, spell checking, etc).'=>'Schimbă atributul lang al etichetei HTML la un format care include sau nu țara/regiunea. <br>În HTML, atributul lang (<html lang="en-US">) ar trebui folosit pentru a specifica limba conținutului textului, astfel încât browserul să poată afișa sau procesa corect conținutul (ex. pentru despărțirea în silabe, stilizare, corectarea ortografică etc.).','Load legacy Language Switcher'=>'Încarcă selectorul de limbă vechi','Applies to all types of language switchers (floating, shortcode, and menu). When enabled, the site will revert to using the original Language Switcher configured in the General Settings tab, replacing the new customizable version. Your existing switcher settings will remain saved, but they will be ignored while this option is active.'=>'Se aplică tuturor tipurilor de selectoare de limbă (flotant, shortcode și meniu). Când este activat, site-ul va reveni la utilizarea selectorului de limbă original configurat în fila Setări generale, înlocuind versiunea nouă personalizabilă. Setările existente ale selectorului vor rămâne salvate, dar vor fi ignorate cât timp această opțiune este activă.','Load legacy SEO Pack Add-On'=>'Încarcă suplimentul SEO Pack vechi','In case the recent migration to the new slug rewrite is causing trouble, set this to Yes to use the old method <br> Please <a href="https://translatepress.com/support/open-ticket/?utm_source=tp-advanced&utm_medium=client-site&utm_campaign=troubleshooting" target="_blank">open a support ticket</a> letting us know of the issues you are having.'=>'În cazul în care migrația recentă la noua rescriere a slug-ului cauzează probleme, setează această opțiune la Da pentru a folosi metoda veche.<br>Te rugăm să <a href="https://translatepress.com/support/open-ticket/?utm_source=tp-advanced&utm_medium=client-site&utm_campaign=troubleshooting" target="_blank">deschizi un tichet de suport</a> pentru a ne informa despre problemele pe care le întâmpini.','Manual Translation Only'=>'Doar traducere manuală','TranslatePress pro-actively scans and saves strings in the database when users access translated pages. <br>This setting disables this functionality and only allows translation and string saving when inside the Translation Editor. <br>Also disables machine translation outside the Translation Editor, giving you better control over character spending, by translating only the pages you visit in the Translation Editor.'=>'TranslatePress scanează proactiv și salvează șirurile în baza de date atunci când utilizatorii accesează paginile traduse. <br>Această setare dezactivează această funcționalitate și permite traducerea și salvarea șirurilor doar în Editorul de traduceri. <br>Dezactivează, de asemenea, traducerea automată în afara Editorului de traduceri, oferindu-ți un control mai bun asupra consumului de caractere, prin traducerea doar a paginilor pe care le vizitezi în Editorul de traduceri.','Open language switcher only on click'=>'Deschide selectorul de limbă doar la clic','Open the language switcher shortcode by clicking on it instead of hovering.<br> Close it by clicking on it, anywhere else on the screen or by pressing the escape key. This will affect only the shortcode language switcher.'=>'Deschide selectorul de limbă shortcode făcând clic pe el în loc să treci cu cursorul peste el.<br>Închide-l făcând clic pe el, oriunde altundeva pe ecran sau apăsând tasta Escape. Aceasta va afecta doar selectorul de limbă shortcode.','Show opposite language in the language switcher'=>'Afișează limba opusă în selectorul de limbă','Transforms the language switcher into a button showing the other available language, not the current one.<br> Only works when there are exactly two languages, the default one and a translation one.<br>This will affect the shortcode language switcher and floating language switcher as well.<br> To achieve this in menu language switcher go to Appearance->Menus->Language Switcher and select Opposite Language.'=>'Transformă selectorul de limbă într-un buton care afișează cealaltă limbă disponibilă, nu pe cea curentă.<br>Funcționează doar când există exact două limbi, cea implicită și una de traducere.<br>Aceasta va afecta și selectorul de limbă shortcode și selectorul de limbă flotant.<br>Pentru a realiza acest lucru în selectorul de limbă din meniu, mergi la Aspect->Meniuri->Selector de limbă și selectează Limba opusă.','<a href="%s">Click here</a> to access the database optimization tool.'=>'<a href="%s">Clic aici</a> pentru a accesa instrumentul de optimizare a bazei de date.','It helps remove possible duplicate translations, clear unnecessary data and repair possible metadata issues.'=>'Ajută la eliminarea posibilelor traduceri duplicate, la ștergerea datelor inutile și la repararea posibilelor probleme de metadate.','<a href="%s" target="_blank">Here</a> you can observe the last 5 SQL errors relevant to TranslatePress if they exist.'=>'<a href="%s" target="_blank">Aici</a> poți vedea ultimele 5 erori SQL relevante pentru TranslatePress, dacă există.','Troubleshooting'=>'Depanare','Exclude Gettext strings'=>'Exclude șirurile Gettext','Debug'=>'Debug','Custom languages'=>'Limbi personalizate','Miscellaneous options'=>'Opțiuni diverse','Exclude strings & pages'=>'Exclude șirurile și paginile','Automatic Translation Memory'=>'Memorie de traducere automată','Serve same translation for similar text. The strings need to have a percentage of 95% similarity.<br>Helps prevent losing existing translation when correcting typos or making minor adjustments to the original text. <br>If a translation already exists for a very similar original string, it will automatically be used for the current original string.<br>Does not work when making changes to a text that is part of a translation block unless the new text is manually merged again in a translation block.<br>Each string needs to have a minimum of 50 characters.'=>'Folosește aceeași traducere pentru text similar. Șirurile trebuie să aibă un procent de similaritate de 95%.<br>Previne pierderea traducerii existente la corectarea greșelilor de tastare sau la efectuarea unor ajustări minore ale textului original. <br>Dacă există deja o traducere pentru un șir original foarte similar, aceasta va fi utilizată automat pentru șirul original curent.<br>Nu funcționează atunci când se fac modificări într-un text care face parte dintr-un bloc de traducere, decât dacă noul text este îmbinat manual din nou într-un bloc de traducere.<br>Fiecare șir trebuie să aibă minimum 50 de caractere.','WARNING: This feature can negatively impact page loading times in secondary languages, particularly with large databases (for example websites with a lot of pages or products). If you experience slow loading times, disable this and try again.'=>'AVERTISMENT: Această funcționalitate poate afecta negativ timpii de încărcare a paginilor în limbile secundare, în special cu baze de date mari (de exemplu, site-uri cu multe pagini sau produse). În caz de timpi de încărcare lenți, dezactivați această opțiune și încercați din nou.','Fix missing dynamic content'=>'Remediere conținut dinamic lipsă','May help fix missing content inserted using JavaScript. <br> It shows dynamically inserted content in original language for a moment before the translation request is finished.'=>'Poate ajuta la remedierea conținutului lipsă inserat prin JavaScript. <br> Afișează conținutul inserat dinamic în limba originală pentru o clipă înainte ca cererea de traducere să fie finalizată.','Filter Gettext wrapping from post content and title'=>'Filtrează încapsularea Gettext din conținutul și titlul articolului','Filters gettext wrapping such as #!trpst#trp-gettext from all updated post content and post title. Does not affect previous post content. <br/><strong>Database backup is recommended before switching on.</strong>'=>'Filtrează încapsularea Gettext, cum ar fi #!trpst#trp-gettext, din conținutul și titlul tuturor articolelor actualizate. Nu afectează conținutul articolelor anterioare. <br/><strong>Se recomandă efectuarea unei copii de rezervă a bazei de date înainte de activare.</strong>','Filter Gettext wrapping from post meta'=>'Filtrează încapsularea Gettext din metadatele articolului','Filters gettext wrapping such as #!trpst#trp-gettext from all updated post meta. Does not affect previous post meta. <br/><strong>Database backup is recommended before switching on.</strong>'=>'Filtrează încapsularea Gettext, cum ar fi #!trpst#trp-gettext, din metadatele tuturor articolelor actualizate. Nu afectează metadatele articolelor anterioare. <br/><strong>Se recomandă efectuarea unei copii de rezervă a bazei de date înainte de activare.</strong>','Google Translate v2'=>'Google Translate v2','Google Translate API Key'=>'Cheie API Google Translate','Add your API Key here...'=>'Adăugați cheia API aici...','Visit <a href="https://cloud.google.com/docs/authentication/api-keys" target="_blank">this link</a> to see how you can set up an API key, <strong>control API costs</strong> and set HTTP referrer restrictions.'=>'Vizitați <a href="https://cloud.google.com/docs/authentication/api-keys" target="_blank">acest link</a> pentru a vedea cum puteți configura o cheie API, <strong>controla costurile API</strong> și seta restricții de referrer HTTP.','Your HTTP referrer is: %s'=>'Referrer-ul HTTP este: %s','There was an error on the server processing your Google Translate key.'=>'A apărut o eroare pe server la procesarea cheii Google Translate.','There was an error with your Google Translate key.'=>'A apărut o eroare cu cheia Google Translate.','Please check your TranslatePress license key.'=>'Vă rugăm să verificați cheia de licență TranslatePress.','TranslatePress AI'=>'TranslatePress AI','No Active License Detected for this website.'=>'Nu a fost detectată nicio licență activă pentru acest site web.','In order to enable Automatic Translation using TranslatePress AI, you need a license key by creating a free account.'=>'Pentru a activa traducerea automată folosind TranslatePress AI, este necesară o cheie de licență obținută prin crearea unui cont gratuit.','Create your Free Account'=>'Creează-ți contul gratuit',' or '=>' sau ','Enter your license key'=>'Introdu cheia de licență',' Or %1$spurchase one here%2$s'=>' Sau %1$scumpără una aici%2$s','Your free account includes: '=>'Contul tău gratuit include: ','Get more AI Words and unlock all AI features with TranslatePress Pro.'=>'Obține mai multe cuvinte AI și deblochează toate funcțiile AI cu TranslatePress Pro.','You have a valid %s <strong>license</strong>.'=>'Ai o <strong>licență</strong> %s validă.',' words remaining. '=>' cuvinte rămase. ','Recheck'=>'Reverifică','Rechecking...'=>'Se reverifică...','Done.'=>'Gata.','Manage your license & quota on the %s'=>'Gestionează-ți licența și cota pe %s','TranslatePress.com Account Page'=>'Pagina de cont TranslatePress.com','SEO support for page slug, page title, description and Facebook and Twitter social graph information. The HTML lang attribute is properly set.'=>'Suport SEO pentru slug-ul paginii, titlul paginii, descrierea și informațiile de social graph pentru Facebook și Twitter. Atributul HTML lang este setat corect.','Enable Modules'=>'Activează modulele','Enable Add-on modules to extend TranslatePress and enhance the functionality of your translated site.'=>'Activează modulele suplimentare pentru a extinde TranslatePress și a îmbunătăți funcționalitatea site-ului tău tradus.','More functionality with TranslatePress Pro.'=>'Mai multă funcționalitate cu TranslatePress Pro.','Already a Pro User?'=>'Ești deja utilizator Pro?','Activate License Key'=>'Activează cheia de licență','This add-on is not available on your current plan.'=>'Această extensie nu este disponibilă în planul tău actual.','Continue'=>'Continuă','The link you followed has expired. Please reload the page and try again.'=>'Linkul pe care l-ai accesat a expirat. Reîncarcă pagina și încearcă din nou.','A valid license is required to enable Automatic Translation.'=>'Este necesară o licență validă pentru a activa traducerea automată.','Your license key is disabled for this URL. Re-enable it from <a target="_blank" href="https://translatepress.com/account/?utm_source=tp-onboarding&utm_medium=client-site&utm_campaign=tp-ai">https://translatepress.com/account</a> -> Manage Sites.'=>'Cheia ta de licență este dezactivată pentru acest URL. Reactiveaz-o din <a target="_blank" href="https://translatepress.com/account/?utm_source=tp-onboarding&utm_medium=client-site&utm_campaign=tp-ai">https://translatepress.com/account</a> -> Gestionare site-uri.','<p><strong>License key mismatch.</strong> The license you entered doesn\'t match the TranslatePress version you have installed.</p><p>Please check that you\'ve installed the correct version for your license from your TranslatePress account.</p>'=>'<p><strong>Cheia de licență nu corespunde.</strong> Licența pe care ai introdus-o nu corespunde cu versiunea de TranslatePress instalată.</p><p>Verifică dacă ai instalat versiunea corectă pentru licența ta din contul tău TranslatePress.</p>','Automatically translate your website using TranslatePress AI.'=>'Traduce automat site-ul tău folosind TranslatePress AI.','In order to enable Automatic Translation using TranslatePress AI, please enter your license key from'=>'Pentru a activa traducerea automată folosind TranslatePress AI, introdu cheia de licență din','your account.'=>'contul tău.','Skip and continue with manual translation »'=>'Sari peste și continuă cu traducerea manuală »','Get Your Free TranslatePress AI License'=>'Obține licența ta gratuită TranslatePress AI','Generate License'=>'Generează licența','Creating a fr